(()=>{"use strict";let e;async function t(t){try{const n=await fetch(`https://api.openweathermap.org/data/2.5/weather?q=${t}&units=metric&APPID=c3c9b94a84922c416cdc3eb8cabb70ad`,{mode:"cors"}),a=await n.json(),c=((e,t,n,a,c,r)=>({getName:()=>e,getTemp:()=>Math.trunc(t)+"º",getMin:()=>Math.trunc(n)+"º",getMax:()=>Math.trunc(a)+"º",getDesc:()=>c,getWind:()=>r+" Km/h"}))(a.name,a.main.temp,a.main.temp_min,a.main.temp_max,a.weather[0].main,a.wind.speed);e=c}catch(e){return}}const n=document.querySelector("#locationName"),a=document.querySelector("#icon"),c=document.querySelector("#temp"),r=document.querySelector("#min"),o=document.querySelector("#max"),m=document.querySelector("#wind"),i=document.querySelector("#searchBar");function p(){n.textContent=e.getName(),c.textContent=e.getTemp(),r.textContent="Min today: "+e.getMin(),o.textContent="Max today: "+e.getMax(),m.textContent="Wind: "+e.getWind(),function(){switch(e.getDesc()){case"Clear":a.src="http://openweathermap.org/img/wn/01d.png";break;case"Clouds":a.src="http://openweathermap.org/img/wn/02d.png";break;case"Rain":a.src="http://openweathermap.org/img/wn/09d.png";break;case"Thunderstorm":a.src="http://openweathermap.org/img/wn/11d.png";break;case"Snow":a.src="http://openweathermap.org/img/wn/13d.png";break;case"Mist":a.src="http://openweathermap.org/img/wn/50d.png"}}(),i.value=""}const s=document.querySelector("#searchBar"),d=document.querySelector("#searchBtn");!async function(){await t("Montevideo"),p()}(),d.addEventListener("click",(async()=>{await t(s.value),p()}))})();